// W121 - load_plaza_list (Fase 0 hardcoded; Fase 1: desde res.partner o gf.plaza)
const plazas = [
  { plaza_id: 'IGUALA',      company_id: 35 },
  { plaza_id: 'GUADALAJARA', company_id: 34 },
  { plaza_id: 'ZAPOPAN',     company_id: 34 },
  { plaza_id: 'TLAQUEPAQUE', company_id: 34 },
];
return plazas.map(p => ({ json: p }));

// W121 - build_search_body (pre-build JSON-RPC body para evitar parser de n8n con arrays anidados)
const plaza = $('load_plaza_list').item.json;
const uid = $('odoo_authenticate').first().json.result;
const body = JSON.stringify({
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      $env.ODOO_DB,
      uid,
      $env.ODOO_PASSWORD,
      'product.product',
      'search_read',
      [[['company_id', '=', plaza.company_id], ['sale_ok', '=', true]]],
      { fields: ['id', 'name', 'default_code', 'uom_id', 'barcode'], limit: 500 }
    ]
  }
});
return { json: { ...plaza, search_body: body } };

// W121 - enrich_with_aliases + pre-build upsert_body (uid disponible desde odoo_authenticate)
const plaza = $('load_plaza_list').item.json;
const uid = $('odoo_authenticate').first().json.result;
const products = $input.item.json.result || [];

function aliasesFor(name) {
  const n = (name || '').toLowerCase();
  const tokens = n.split(/[\s\-\/]+/).filter(Boolean);
  return Array.from(new Set(tokens));
}

const skus = products.map(p => ({
  id: p.id,
  name: p.name,
  code: p.default_code || null,
  uom: p.uom_id?.[1] || null,
  aliases: aliasesFor(p.name),
}));

const payload = {
  plaza_id: plaza.plaza_id,
  company_id: plaza.company_id,
  version: new Date().toISOString(),
  skus,
  sku_count: skus.length,
};

const upsert_body = JSON.stringify({
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      $env.ODOO_DB,
      uid,
      $env.ODOO_PASSWORD,
      'kold.voice.catalog',
      'upsert_by_plaza',
      [plaza.plaza_id, plaza.company_id, payload]
    ]
  }
});

return { json: { ...payload, upsert_body } };

// W121 - set_static_data + anomaly detection
const p = $('enrich_with_aliases').item.json;
const upsertResp = $input.item.json?.result;
const dropPct = Number(upsertResp?.drop_pct ?? 0);
const prevCount = Number(upsertResp?.previous_sku_count ?? 0);

// Cache en static data del workflow (cache rapido para W120 read).
// Nota: solo persistimos los campos del catalogo, NO upsert_body (transient).
const { upsert_body, ...catalogPayload } = p;
const data = $getWorkflowStaticData('global');
data[`cat_${p.plaza_id}`] = catalogPayload;

// Log si falla upsert
if ($input.item.json?.error) {
  console.log('[W121 upsert FAIL]', 'plaza=' + p.plaza_id, 'error=' + JSON.stringify($input.item.json.error));
}

return { json: {
  plaza_id: p.plaza_id,
  sku_count: p.sku_count,
  prev_sku_count: prevCount,
  drop_pct: dropPct,
  alert: dropPct > 30,
}};
